INSERT INTO ar_accounting_scheme (id, version, created, code, description, script_instance_id, long_description_i18n) VALUES (nextval('ar_accounting_scheme_seq'), 0, NOW(), 'Dual entry scheme', 'Default Accounting Scheme', (SELECT id FROM meveo_script_instance WHERE code='org.meveo.service.script.accountingscheme.DefaultAccountingSchemeScript'), '{"FRA":"<p>Ce schéma produit 2 lignes d''écriture:</p><ul><li>Une ligne pour le compte et le sens définis sur le type d''opération de de compte</li><li>Une ligne pour le compte de contrepartie défini sur le type d''opération de compte, mais avec un sens opposé</li></ul>","ENG":"<p>This scheme produces 2 accounting entries:</p><ul><li>An entry for the accounting code and the direction defined on the account operation type</li><li>An entry for the contra account defined on the account operation, type but with the opposite direction</li></ul>"}');
INSERT INTO databasechangelog (ID, AUTHOR, FILENAME, DATEEXECUTED, ORDEREXECUTED, MD5SUM, DESCRIPTION, COMMENTS, EXECTYPE, CONTEXTS, LABELS, LIQUIBASE, DEPLOYMENT_ID) VALUES ('#INTRD-5955_20220324', 'aelmalki', 'src/main/db_resources/changelog/rebuild/data-demo.xml', NOW(), 4643, '8:3d86360141b15fb97777e09741abe543', 'insert tableName=ar_accounting_scheme', '', 'EXECUTED', NULL, NULL, '3.8.0', '2458462777');
INSERT INTO meveo_script_instance (id, version, code, src_type, description, created, script_instance_cat_id) VALUES (nextval('meveo_script_instance_seq'), 0, 'org.meveo.service.script.accountingscheme.InvoiceAccountingSchemeScript', 'JAVA_CLASS', 'Invoice accounting scheme script', NOW(), (SELECT id FROM meveo_script_instance_cat WHERE code='ACCOUNTING_SCHEMES'));
INSERT INTO ar_accounting_scheme (id, version, created, code, description, script_instance_id, long_description_i18n) VALUES (nextval('ar_accounting_scheme_seq'), 0, NOW(), 'Invoice and Credit Note', 'Invoice accounting scheme', (SELECT id FROM meveo_script_instance WHERE code='org.meveo.service.script.accountingscheme.InvoiceAccountingSchemeScript'), '{"FRA":"<p>Ce schéma produit des lignes d''écritures pour une facture ou un avoir (ci-dessous \"document\") :</p><ul><li>Une ligne unique pour le total TTC du document, sur le compte client (de la catégorie de client ou à défaut du type d''opération de compte).</li></ul><p class=\"ql-indent-1\">Le sens est celui de l''opération de compte (pour une facture : DEBIT, pour un avoir : CREDIT).</p><ul><li>Des lignes de contrepartie (au moins une) pour les montants HT pour les comptes de revenus, en utilisant les codes comptables des articles liés aux lignes du document.</li></ul><p class=\"ql-indent-1\">Le sens est l''opposé de celui du type d''opération (pour une facture : CREDIT, pour un avoir : DEBIT).</p><ul><li>S''il y a lieu, des lignes pour les montants des différentes taxes appliquées au document, en utilisant les codes comptables de ces taxes.</li></ul><p class=\"ql-indent-1\">Le sens est l''opposé de celui du type d''opération (pour une facture : CREDIT, pour un avoir : DEBIT).</p>","ENG":"<p>This scheme produces entries for an invoice or credit note (here after \"document\"):</p><ul><li>A single entry with the document total amount with tax using the customer accounting code (from the customer category, or if not set from the account operation type). </li></ul><p class=\"ql-indent-1\">Line direction is the one from the account operation type (for invoice: DEBIT, for credit note: CREDIT).</p><ul><li>\"Contra\" entries (at least one) with the amounts without tax for revenue accounts, using the accounting codes from the article linked to the document lines. </li></ul><p class=\"ql-indent-1\">Line direction is the opposite of direction set on the account operation type (for invoices: CREDIT, for credit note: DEBIT).</p><ul><li>\"Contra\" entries (if applies) with the tax amounts for the different taxes applied on the document, using the accounting codes from these taxes.</li></ul><p class=\"ql-indent-1\">Line direction is the opposite of direction set on the account operation type (for invoices: CREDIT, for credit note: DEBIT).</p>"}');
INSERT INTO databasechangelog (ID, AUTHOR, FILENAME, DATEEXECUTED, ORDEREXECUTED, MD5SUM, DESCRIPTION, COMMENTS, EXECTYPE, CONTEXTS, LABELS, LIQUIBASE, DEPLOYMENT_ID) VALUES ('#INTRD-5992_20220329', 'aelmalki', 'src/main/db_resources/changelog/rebuild/data-demo.xml', NOW(), 4645, '8:98ecb3e5ad4faf4497ad21195213c478', 'insert tableName=meveo_script_instance; insert tableName=ar_accounting_scheme', '', 'EXECUTED', NULL, NULL, '3.8.0', '2458462777');
