\"/>\r\n   <field name=\"OC_PARAMETER_9\" ignore=\"true\"/>\r\n  <field name=\"OC_DATE_PARAM_1\" ignore=\"true\"/>\r\n   <field name=\"OC_DATE_PARAM_2\" ignore=\"true\"/>\r\n  <field name=\"OC_DATE_PARAM_3\" ignore=\"true\"/>\r\n   <field name=\"OC_DATE_PARAM_4\" ignore=\"true\"/>\r\n  <field name=\"OC_DATE_PARAM_5\" ignore=\"true\"/>\r\n  <field name=\"OC_DECIMAL_PARAM_1\" ignore=\"true\"/>\r\n  <field name=\"OC_DECIMAL_PARAM_2\" ignore=\"true\"/>\r\n   <field name=\"OC_DECIMAL_PARAM_3\" ignore=\"true\"/>\r\n   <field name=\"OC_DECIMAL_PARAM_4\" ignore=\"true\"/>\r\n   <field name=\"OC_DECIMAL_PARAM_5\" ignore=\"true\"/>\r\n  <field name=\"OC_EXTRA_PARAM\" ignore=\"true\"/>\r\n  </record>\r\n  <record name=\"details\" minOccurs=\"1\" maxOccurs=\"unbounded\" class=\"map\">\r\n  <field name=\"OC_CDR_DATE\" required=\"true\"/>\r\n  <field name=\"OC_QANTITY\" required=\"true\"/>\r\n  <field name=\"OC_AC\" required=\"true\"/>\r\n   <field name=\"OC_PARAMETER_1\"/>\r\n  <field name=\"OC_PARAMETER_2\"/>\r\n  <field name=\"OC_PARAMETER_3\" />\r\n   <field name=\"OC_PARAMETER_4\" />\r\n  <field name=\"OC_PARAMETER_5\" />\r\n  <field name=\"OC_PARAMETER_6\" />\r\n  <field name=\"OC_PARAMETER_7\" />\r\n <field name=\"OC_PARAMETER_8\" />\r\n <field name=\"OC_PARAMETER_9\" />\r\n  <field name=\"OC_DATE_PARAM_1\"/>\r\n  <field name=\"OC_DATE_PARAM_2\"/>\r\n <field name=\"OC_DATE_PARAM_3\" />\r\n  <field name=\"OC_DATE_PARAM_4\" />\r\n  <field name=\"OC_DATE_PARAM_5\" />\r\n   <field name=\"OC_DECIMAL_PARAM_1\"/>\r\n  <field name=\"OC_DECIMAL_PARAM_2\"/>\r\n <field name=\"OC_DECIMAL_PARAM_3\" />\r\n <field name=\"OC_DECIMAL_PARAM_4\" />\r\n  <field name=\"OC_DECIMAL_PARAM_5\" />\r\n  <field name=\"OC_EXTRA_PARAM\" />\r\n  </record>\r\n  </stream>\r\n  </beanio>\r\n"}], "FlatFileProcessingJob_scriptsFlow": [{"string": "org.meveo.service.script.CdrCsvImportScript"}], "FlatFileProcessingJob_formatTransfo": [{"string": "None"}], "FlatFileProcessingJob_originFilename": [{"string": "or