CREATE TABLE databasechangelog (ID VARCHAR(255) NOT NULL, AUTHOR VARCHAR(255) NOT NULL, FILENAME VARCHAR(255) NOT NULL, DATEEXECUTED TIMESTAMP WITHOUT TIME ZONE NOT NULL, ORDEREXECUTED INTEGER NOT NULL, EXECTYPE VARCHAR(10) NOT NULL, MD5SUM VARCHAR(35), DESCRIPTION VARCHAR(255), COMMENTS VARCHAR(255), TAG VARCHAR(255), LIQUIBASE VARCHAR(20), CONTEXTS VARCHAR(255), LABELS VARCHAR(255), DEPLOYMENT_ID VARCHAR(10));

-- Changeset src/main/db_resources/changelog/rebuild/structure.xml::rebuild_pg_operators::AndriusKarpavicius
CREATE OPERATOR ^|(
			  PROCEDURE = jsonb_exists_any,
			  LEFTARG = jsonb,
			  RIGHTARG = _text,
			  RESTRICT = contsel,
			  JOIN = contjoinsel);

CREATE OPERATOR CLASS jsonb_ops_custom
			   FOR TYPE jsonb USING gin AS
			   OPERATOR 10  ^|(jsonb, _text),
			   FUNCTION 1  gin_compare_jsonb(text, text),
			   FUNCTION 2  gin_extract_jsonb(jsonb, internal, internal),
			   FUNCTION 3  gin_extract_jsonb_query(jsonb, internal, smallint, internal, internal, internal, internal),
			   FUNCTION 4  gin_consistent_jsonb(internal, smallint, jsonb, integer, internal, internal, internal, internal),
			   FUNCTION 6  gin_triconsistent_jsonb(internal, smallint, jsonb, integer, internal, internal, internal);


