            		public class ValidateCreditCategory extends ValidateCreditCategoryScript {}', NOW(), 'OPENCELL.ADMIN', 1, 'JAVA', 'The customer''s (customer account actually) credit category must not be in the provided list for the rule to pass. If customer''s credit category is in the list, the rule will fail. If credit category list is empty, then rule will be ignored.', '{"ENG":"<p>The customer''s (customer account actually) credit category must not be in the provided list for the rule to pass.</p><p>If customer''s credit category is in the list, the rule will fail.</p><p>If credit category list is empty, then rule will be ignored.</p>","FRA":"<p>Le catégorie de crédit du client (customer account) ne doit pas être dans la liste fournie pour que la règle passe.</p><p>Si la catégorie de crédit du client est dans la liste, la règle va échouer.</p><p>Si la liste de catégories de crédit est vide, la règle sera ignorée.</p>"}', (SELECT id FROM meveo_script_instance_cat WHERE code='INVOICE_VALIDATION'));



